let image_asset_id = null;
let audio_asset_id = null;
let image_url = null;
let audio_url = null;

for (const item of items) {
  const { type, id, asset } = item.json;

  if (type === 'image') {
    image_asset_id = id;
    image_url = asset?.url || null;
  } else if (type === 'audio') {
    audio_asset_id = id;
    audio_url = asset?.url || null;
  }
}

return [
  {
    json: {
      image_asset_id,
      audio_asset_id,
      image_url,
      audio_url
    }
  }
];

